#### 任务 0.1: 完善 WebSocket 实时通信 (2天)

**目标**: 前后端 WebSocket 稳定连接,实时数据推送

**前端工作**:
```typescript
// stores/websocket.ts - 完善 WebSocket Store
export const useWebSocketStore = defineStore('websocket', () => {
  const isConnected = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5
  const socket = ref<WebSocket | null>(null)

  // 事件监听器映射
  const listeners = new Map<string, Set<Function>>()

  function connect() {
    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/api/ws'
    socket.value = new WebSocket(wsUrl)

    socket.value.onopen = () => {
      isConnected.value = true
      reconnectAttempts.value = 0
      console.log('✅ WebSocket connected')

      // 订阅所有频道
      subscribe('iterations')
      subscribe('agents')
      subscribe('logs')
      subscribe('metrics')
    }

    socket.value.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data)
        const { event: eventType, data } = message

        // 触发监听器
        const eventListeners = listeners.get(eventType)
        if (eventListeners) {
          eventListeners.forEach(callback => callback(data))
        }
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    socket.value.onclose = () => {
      isConnected.value = false
      console.log('🔴 WebSocket disconnected')

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.value), 30000)
        setTimeout(() => {
          reconnectAttempts.value++
          console.log(`🔄 Reconnecting... (${reconnectAttempts.value}/${maxReconnectAttempts})`)
          connect()
        }, delay)
      }
    }

    socket.value.onerror = (error) => {
      console.error('WebSocket error:', error)
    }
  }

  function subscribe(channel: string) {
    send({ event: 'subscribe', channel })
  }

  function unsubscribe(channel: string) {
    send({ event: 'unsubscribe', channel })
  }

  function send(data: any) {
    if (socket.value?.readyState === WebSocket.OPEN) {
      socket.value.send(JSON.stringify(data))
    }
  }

  function on(event: string, callback: Function) {
    if (!listeners.has(event)) {
      listeners.set(event, new Set())
    }
    listeners.get(event)!.add(callback)
  }

  function off(event: string, callback: Function) {
    const eventListeners = listeners.get(event)
    if (eventListeners) {
      eventListeners.delete(callback)
    }
  }

  function disconnect() {
    if (socket.value) {
      socket.value.close()
      socket.value = null
    }
  }

  return {
    isConnected,
    connect,
    disconnect,
    subscribe,
    unsubscribe,
    on,
    off,
    send
  }
})
```

**后端工作**:
```typescript
// services/realtime.service.ts - 完善实时服务
export class RealtimeService {
  private clients: Set<WebSocket> = new Set()
  private subscriptions: Map<WebSocket, Set<string>> = new Map()
  private heartbeatIntervals: Map<WebSocket, NodeJS.Timeout> = new Map()

  constructor(private logger: pino.Logger) {}

  addClient(socket: WebSocket) {
    this.clients.add(socket)
    this.subscriptions.set(socket, new Set())

    // 启动心跳
    this.startHeartbeat(socket)
  }

  removeClient(socket: WebSocket) {
    this.clients.delete(socket)
    this.subscriptions.delete(socket)

    const interval = this.heartbeatIntervals.get(socket)
    if (interval) {
      clearInterval(interval)
      this.heartbeatIntervals.delete(socket)
    }
  }

  subscribe(socket: WebSocket, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.add(channel)
      this.logger.info({ channel }, 'Client subscribed')
    }
  }

  unsubscribe(socket: WebSocket, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.delete(channel)
      this.logger.info({ channel }, 'Client unsubscribed')
    }
  }

  broadcast(event: string, data: any, channel?: string) {
    const message = JSON.stringify({ event, data })

    this.clients.forEach(socket => {
      if (channel) {
        const channels = this.subscriptions.get(socket)
        if (!channels?.has(channel) && !channels?.has('all')) {
          return
        }
      }

      if (socket.readyState === WebSocket.OPEN) {
        socket.send(message)
      }
    })
  }

  broadcastIteration(iteration: Iteration) {
    this.broadcast('iteration.status_changed', iteration)
  }

  broadcastAgent(agent: Agent) {
    this.broadcast('agent.status_changed', agent)
  }

  broadcastMetrics(metrics: any) {
    this.broadcast('system.metrics', metrics)
  }

  broadcastLog(log: LogEntry) {
    this.broadcast('log.entry', log)
  }

  private startHeartbeat(socket: WebSocket) {
    const interval = setInterval(() => {
      if (socket.readyState === WebSocket.OPEN) {
        socket.send(JSON.stringify({ event: 'ping' }))
      } else {
        clearInterval(interval)
        this.heartbeatIntervals.delete(socket)
      }
    }, 30000)

    this.heartbeatIntervals.set(socket, interval)
  }

  handlePong(socket: WebSocket) {
    // 心跳响应,连接正常
  }
}
```

**验收标准**:
- ✅ WebSocket 自动重连成功率 > 95%
- ✅ 实时数据延迟 < 200ms
- ✅ 支持频道订阅/取消订阅
- ✅ 心跳机制正常工作

