import { ref, computed, onMounted } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { useIterationStore } from '@/stores/iteration'
import { dashboardApi } from '@/api/dashboard'

const iterationStore = useIterationStore()
const loading = ref(false)
const searchKeyword = ref('')
const statusFilter = ref('')
const dateRange = ref([])
const sortBy = ref('createdAt')
const currentPage = ref(1)
const pageSize = ref(20)
const iterations = ref<any[]>([])
const total = ref(0)
const detailDialogVisible = ref(false)
const selectedIteration = ref(null)

const filteredIterations = computed(() => {
  return iterations.value.filter(iteration => {
    if (searchKeyword.value && !iteration.requirement.includes(searchKeyword.value)) {
      return false
    }
    if (statusFilter.value && iteration.status !== statusFilter.value) {
      return false
    }
    return true
  })
})

async function loadIterations() {
  loading.value = true
  try {
    const response = await dashboardApi.getIterations({
      page: currentPage.value,
      pageSize: pageSize.value
    })
    iterations.value = response.data
    total.value = response.total
  } catch (error) {
    ElMessage.error('加载迭代列表失败')
  } finally {
    loading.value = false
  }
}

function handleSearch() {
  // 搜索逻辑
}

function handleFilter() {
  // 筛选逻辑
}

function handleSort() {
  // 排序逻辑
}

function viewDetail(iteration: any) {
