  detailDialogVisible.value = true
}

async function rollback(iteration: any) {
  try {
    await ElMessageBox.confirm(
      `确定要回滚到迭代 #${iteration.iterationNumber} 吗？`,
      '确认回滚',
      { type: 'warning' }
    )

    await dashboardApi.rollbackIteration(iteration.id)
    ElMessage.success('回滚成功')
    loadIterations()
  } catch (error) {
    if (error !== 'cancel') {
      ElMessage.error('回滚失败')
    }
  }
}

function refresh() {
  loadIterations()
}

onMounted(() => {
  loadIterations()
})
</script>
